        target=lev*ymax
        for t,y in ts:
            if y>=target:
                out[lev]=round(t,2); break
    return out
for s in sorted(rows):
    if 'cd:0_' in s: continue
    print(s.replace('_P0','').replace('m0:3e-6',''), crossings(rows[s]))
